document.addEventListener("DOMContentLoaded",()=>{const e=document.getElementById("chat-widget-button");const t=document.getElementById("chat-widget-container");const n=document.getElementById("close-chat");const s=document.getElementById("chat-input");const o=document.getElementById("chat-send");const c=document.getElementById("chat-messages");if(!e||!t)return;e.addEventListener("click",()=>{t.classList.toggle("hidden")});n.addEventListener("click",()=>{t.classList.add("hidden")});o.addEventListener("click",r);s.addEventListener("keypress",e=>{if(e.key==="Enter")r()});async function r(){const e=s.value.trim();if(!e)return;a(e,"user");s.value="";const t=a("...","bot");try{const n=await fetch("chat_endpoint.php",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({contents:[{parts:[{text:"You are a helpful space exploration guide for this website. Respond to the user: "+e}]}]})});const o=await n.json();t.remove();if(o.error){console.error("Gemini API error:",o);a(o.details||o.error||"Unable to reach Gemini API.","bot")}else if(o.candidates&&o.candidates[0]?.content?.parts?.[0]?.text){a(o.candidates[0].content.parts[0].text,"bot")}else{a("I'm sorry, I couldn't process that request.","bot")}}catch(e){console.error("Chat Error:",e);t.remove();a("Error connecting to Gemini API.","bot")}}function a(e,t){const n=document.createElement("div");n.classList.add("chat-message",`${t}-message`);if(t==="bot"){n.innerHTML=marked.parse(e)}else{n.textContent=e}c.appendChild(n);c.scrollTop=c.scrollHeight;return n}});